6	//! Experimental, rustc-independent cuda-oxide PTX backend.
7	//!
8	//! The only supported public surface is [`experimental`]. It accepts a module
9	//! assembled from cuda-oxide's `dialect-mir` and `dialect-nvvm` operations and
10	//! produces PTX through the same MIR preparation, lowering, and LLVM tools as
11	//! the rustc frontend.
12	//!
13	//! This crate intentionally has no rustc linkage. It does not require
14	//! `rustc_private` or a nightly toolchain matched to `rustc_driver`.
15	
16	#![warn(missing_docs)]
17	
18	mod api;
19	mod error;
20	mod export;
21	mod llvm_tools;
22	mod lower;
23	mod options;
24	mod pipeline;
25	mod prep;
26	mod ptx;
27	mod target;
28	mod verify;
