30	/// Experimental standalone code-generation API.
31	///
32	/// # Version contract
33	///
34	/// This API is an experimental v1. It is source-compatible only with the exact
35	/// cuda-oxide revision that supplies it. Frontends must pin cuda-oxide, Pliron,
36	/// `dialect-mir`, and `dialect-nvvm` to one revision; their in-memory IR is not
37	/// a stable interchange format.
38	///
39	/// # Accepted input
40	///
41	/// A [`CodegenModule`](experimental::CodegenModule) owns the Pliron context
42	/// that created its module. Its top-level operation may contain `dialect-mir`,
43	/// `dialect-nvvm`, and builtin operations accepted by cuda-oxide's normal
44	/// lowering pipeline. Kernel entries are top-level
45	/// [`dialect_mir::ops::MirFuncOp`] values whose symbols are marked through
46	/// [`CodegenModule::mark_kernel_entry`](experimental::CodegenModule::mark_kernel_entry).
47	/// The v1 PTX output must be self-contained: libdevice calls and other
48	/// unresolved functions return
49	/// [`CompileError::UnsupportedLinking`](experimental::CompileError::UnsupportedLinking).
50	///
51	/// # Minimal flow
52	///
53	/// ```no_run
54	/// use cuda_oxide_codegen::experimental::{
55	///     CodegenModule, CompileOptions, Compiler, Target,
56	/// };
57	///
58	/// # fn main() -> Result<(), Box<dyn std::error::Error>> {
59	/// let mut module = CodegenModule::new("frontend_module")?;
60	/// module.edit(|ctx, root| {
61	///     // Build top-level dialect-mir functions in `root` with their owner `ctx`.
62	///     let _ = (ctx, root);
63	/// });
64	///
65	/// let compiler = Compiler::discover()?;
66	/// let options = CompileOptions::new(Target::parse("sm_90")?);
67	/// let ptx = compiler.compile(&mut module, &options)?.into_ptx();
68	/// assert!(!ptx.is_empty());
69	/// # Ok(())
70	/// # }
71	/// ```
72	///
73	/// # LLVM tools
74	///
75	/// Compilation shells out to `llc` and, for
76	/// [`Optimization::O2`](experimental::Optimization::O2), a matching `opt`.
77	/// LLVM 21 is the general floor; targets that require PTX 9.0 need LLVM 22.
78	/// [`Toolchain`](experimental::Toolchain) discovers these programs explicitly
79	/// or accepts caller-supplied paths.
80	///
81	/// # Execution model
82	///
83	/// Compilation is synchronous. V1 has no cache, cancellation, or link step.
84	/// A module is cloned before destructive compiler passes, so the caller's IR
85	/// remains available and may be compiled repeatedly. Different threads may
86	/// create and compile independent
87	/// [`CodegenModule`](experimental::CodegenModule) values in place; the backend
88	/// has no global compilation lock. A module itself is not promised to be
89	/// `Send` and cannot be edited while it is being compiled.
90	pub mod experimental {
91	    pub use crate::api::{
92	        CodegenModule, Compilation, CompilationStage, CompileError, CompileOptions, Compiler,
93	        DebugInfo, Diagnostic, DiagnosticLevel, Optimization, Target, Toolchain,
94	    };
95	}
96	
97	/// Existing cross-crate implementation hooks for mir-importer.
98	///
99	/// This is not part of the experimental standalone frontend contract.
100	#[doc(hidden)]
101	pub mod __private {
102	    #[doc(hidden)]
103	    pub use crate::error::PipelineError;
104	    #[doc(hidden)]
105	    pub use crate::export::{DeviceExternAttrs, DeviceExternDecl};
106	    #[doc(hidden)]
107	    pub use crate::lower::append_to_module;
108	    #[doc(hidden)]
109	    pub use crate::options::BackendOptions;
110	    #[doc(hidden)]
111	    pub use crate::pipeline::{
112	        ModuleArtifactKind, ModulePipelineOutput, ModulePipelineRequest, OutputFiles,
113	        PipelineTrace, compile_translated_module,
114	    };
115	    #[doc(hidden)]
116	    pub use crate::verify::verify_operation;
117	    #[doc(hidden)]
118	    pub use llvm_export::export::DeviceExternType;
119	}
120	
121	#[cfg(test)]
122	mod tests {
123	    use super::experimental::CodegenModule;
124	
125	    #[test]
126	    fn codegen_module_registers_dialects() {
127	        let mut module = CodegenModule::new("test").unwrap();
128	        module.edit(|ctx, _| {
129	            dialect_mir::register(ctx);
130	            dialect_nvvm::register(ctx);
131	        });
132	    }
133	}
