1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	use crate::error::PipelineError;
7	use crate::llvm_tools::{LlvmToolchain, OptTool, probe_runnable};
8	use crate::options::BackendOptions;
9	use crate::pipeline::{
10	    ModuleArtifactKind, ModulePipelineRequest, OutputFiles, compile_translated_module,
11	};
12	use libnvvm_sys::CudaArch;
13	use llvm_export::export::DebugKind;
14	use pliron::builtin::{
15	    attributes::{IdentifierAttr, StringAttr},
16	    op_interfaces::ATTR_KEY_SYM_NAME,
17	    ops::ModuleOp,
18	};
19	use pliron::context::Context;
20	use pliron::identifier::Identifier;
21	use pliron::irbuild::{
22	    cloning::{IrMapping, clone_operation},
23	    listener::DummyListener,
24	    rewriter::IRRewriter,
25	};
26	use pliron::linked_list::ContainsLinkedList;
27	use pliron::op::Op;
28	use pliron::operation::Operation;
29	use std::path::{Path, PathBuf};
30	use std::str::FromStr;
31	use std::sync::atomic::{AtomicU64, Ordering};
32	
33	static COMPILATION_COUNTER: AtomicU64 = AtomicU64::new(0);
34	
35	/// A validated CUDA GPU target such as `sm_80`, `sm_90a`, or `sm_120`.
36	#[derive(Clone, Debug, PartialEq, Eq, Hash)]
37	pub struct Target(CudaArch);
38	
39	impl Target {
40	    /// Parse and validate a CUDA target.
41	    pub fn parse(target: &str) -> Result<Self, CompileError> {
42	        target.parse()
43	    }
44	
45	    /// Render the canonical `sm_XX` spelling used by LLVM and PTX.
46	    pub fn sm(&self) -> String {
47	        self.0.sm()
48	    }
49	
50	    /// Numeric CUDA compute capability (`80`, `90`, `120`, ...).
51	    pub fn capability(&self) -> u32 {
52	        self.0.capability()
53	    }
54	
55	    /// Optional architecture-family suffix (`a` or `f`).
56	    pub fn suffix(&self) -> Option<char> {
57	        self.0.suffix()
58	    }
59	}
60	
61	impl FromStr for Target {
62	    type Err = CompileError;
63	
64	    fn from_str(target: &str) -> Result<Self, Self::Err> {
65	        let trimmed = target.trim();
66	        let arch = trimmed
67	            .parse::<CudaArch>()
68	            .map_err(|error| CompileError::InvalidTarget {
69	                target: target.to_string(),
70	                reason: error.to_string(),
71	            })?;
72	        Ok(Self(arch))
73	    }
74	}
75	
76	impl std::fmt::Display for Target {
77	    fn fmt(&self, formatter: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
78	        self.0.fmt(formatter)
79	    }
80	}
81	
82	/// LLVM middle-end policy for one compilation.
83	#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
84	pub enum Optimization {
85	    /// Feed verified, unoptimized LLVM IR directly to `llc`.
86	    None,
87	    /// Require a same-major `opt` and run `opt -O2`.
88	    #[default]
89	    O2,
90	}
91	
92	/// Device debug information policy.
93	#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
94	pub enum DebugInfo {
95	    /// Do not emit debug metadata.
96	    #[default]
97	    None,
98	    /// Preserve variables and compile at `-O0` for cuda-gdb-style debugging.
99	    Full,
100	}
101	
102	/// Typed options for one standalone PTX compilation.
103	#[derive(Clone, Debug)]
104	#[non_exhaustive]
105	pub struct CompileOptions {
106	    target: Target,
107	    optimization: Optimization,
108	    fma_contraction: bool,
109	    debug_info: DebugInfo,
110	}
111	
112	impl CompileOptions {
113	    /// Create optimized, non-debug options for `target`.
114	    pub fn new(target: Target) -> Self {
115	        Self {
116	            target,
117	            optimization: Optimization::O2,
118	            fma_contraction: true,
119	            debug_info: DebugInfo::None,
120	        }
121	    }
122	
123	    /// Select the LLVM optimization policy.
124	    pub fn with_optimization(mut self, optimization: Optimization) -> Self {
125	        self.optimization = optimization;
126	        self
127	    }
128	
129	    /// Allow or forbid ordinary multiply/add contraction into FMA.
130	    pub fn with_fma_contraction(mut self, allow: bool) -> Self {
131	        self.fma_contraction = allow;
132	        self
133	    }
134	
135	    /// Select device debug information.
136	    ///
137	    /// [`DebugInfo::Full`] must be paired with [`Optimization::None`].
138	    pub fn with_debug_info(mut self, debug_info: DebugInfo) -> Self {
139	        self.debug_info = debug_info;
140	        self
141	    }
142	
143	    /// Requested CUDA target.
144	    pub fn target(&self) -> &Target {
145	        &self.target
146	    }
147	
148	    /// Requested LLVM optimization policy.
149	    pub fn optimization(&self) -> Optimization {
150	        self.optimization
151	    }
152	
153	    /// Whether ordinary floating-point operations may contract into FMA.
154	    pub fn fma_contraction(&self) -> bool {
155	        self.fma_contraction
156	    }
157	
158	    /// Requested device debug-information tier.
159	    pub fn debug_info(&self) -> DebugInfo {
160	        self.debug_info
161	    }
162	}
163	
164	/// Severity of a compiler diagnostic.
165	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
166	pub enum DiagnosticLevel {
167	    /// Informational context about a successful operation.
168	    Note,
169	    /// A recoverable condition the caller may want to show.
170	    Warning,
171	    /// A compilation failure.
172	    Error,
173	}
174	
175	/// Stage that produced a diagnostic or error.
176	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
177	#[non_exhaustive]
178	pub enum CompilationStage {
179	    /// Module construction, target parsing, or option validation.
180	    Input,
181	    /// dialect-mir verification, mem2reg, or annotated loop unrolling.
182	    MirPreparation,
183	    /// dialect-mir to LLVM-dialect conversion.
184	    Lowering,
185	    /// Validation that the PTX artifact is self-contained.
186	    Linking,
187	    /// LLVM-dialect to textual LLVM IR export.
188	    Export,
189	    /// LLVM `opt` execution.
190	    Optimization,
191	    /// LLVM `llc` execution or PTX file handling.
192	    Codegen,
193	    /// LLVM tool discovery and compatibility checks.
194	    Toolchain,
195	}
196	
197	/// Structured compiler diagnostic retained for the caller.
198	#[derive(Clone, Debug, PartialEq, Eq)]
199	#[non_exhaustive]
200	pub struct Diagnostic {
201	    /// Diagnostic severity.
202	    pub level: DiagnosticLevel,
203	    /// Compiler stage that produced the diagnostic.
204	    pub stage: CompilationStage,
205	    /// Human-readable detail suitable for logs or a UI.
206	    pub message: String,
207	}
208	
209	impl Diagnostic {
210	    fn note(stage: CompilationStage, message: impl Into<String>) -> Self {
211	        Self {
212	            level: DiagnosticLevel::Note,
213	            stage,
214	            message: message.into(),
215	        }
216	    }
217	
218	    fn warning(stage: CompilationStage, message: impl Into<String>) -> Self {
219	        Self {
220	            level: DiagnosticLevel::Warning,
221	            stage,
222	            message: message.into(),
223	        }
224	    }
225	}
226	
227	/// A cuda-oxide module paired permanently with the Pliron context that owns it.
228	///
229	/// Pliron pointers are arena keys and do not carry a context identity. The
230	/// compiler therefore retains the owner of its root module. Raw handles that a
231	/// callback copies out of [`CodegenModule::edit`] or [`CodegenModule::inspect`]
232	/// remain the caller's responsibility.
233	pub struct CodegenModule {
234	    context: Context,
235	    module: ModuleOp,
236	}
237	
238	impl CodegenModule {
239	    /// Create a module and register every dialect accepted by experimental v1.
240	    pub fn new(name: &str) -> Result<Self, CompileError> {
241	        let name: Identifier = name
242	            .try_into()
243	            .map_err(|_| CompileError::InvalidModuleName {
244	                name: name.to_string(),
245	            })?;
246	        let mut context = Context::new();
247	        dialect_mir::register(&mut context);
248	        dialect_nvvm::register(&mut context);
249	        let module = ModuleOp::new(&mut context, name);
250	        Ok(Self { context, module })
251	    }
252	
253	    /// Build or edit IR through the context that owns this compiler root.
254	    ///
255	    /// The callback can still copy raw Pliron handles out of this method.
256	    /// Callers must not resolve those handles in another context or after the
257	    /// referenced operation has been erased.
258	    pub fn edit<R>(&mut self, edit: impl FnOnce(&mut Context, &ModuleOp) -> R) -> R {
259	        edit(&mut self.context, &self.module)
260	    }
261	
262	    /// Inspect IR through the context that owns this compiler root.
263	    ///
264	    /// Returning a raw Pliron handle does not attach a context identity to it;
265	    /// the caller remains responsible for its later use.
266	    pub fn inspect<R>(&self, inspect: impl FnOnce(&Context, &ModuleOp) -> R) -> R {
267	        inspect(&self.context, &self.module)
268	    }
269	
270	    /// Mark one owned top-level `dialect-mir` function as a PTX kernel entry.
271	    ///
272	    /// `symbol` is resolved inside this module's own context. Device helper
273	    /// functions should not be marked. Compilation copies the marker to the
274	    /// lowered LLVM function and exports it as a PTX `.entry`.
275	    pub fn mark_kernel_entry(&mut self, symbol: &str) -> Result<(), CompileError> {
276	        let module = self.module.get_operation();
277	        module
278	            .try_deref(&self.context)
279	            .map_err(|error| CompileError::InvalidModule {
280	                message: format!("the owned module operation is no longer valid: {error:?}"),
281	            })?;
282	        if Operation::get_op::<ModuleOp>(module, &self.context).is_none() {
283	            return Err(CompileError::InvalidModule {
284	                message: "the owned module pointer no longer refers to a builtin.module"
285	                    .to_string(),
286	            });
287	        }
288	        let function = {
289	            let region_count = module.deref(&self.context).regions().count();
290	            if region_count != 1 {
291	                return Err(CompileError::InvalidModule {
292	                    message: format!(
293	                        "cannot mark `{symbol}` as a kernel: the module has {region_count} regions, expected exactly one"
294	                    ),
295	                });
296	            }
297	            let region = module.deref(&self.context).get_region(0);
298	            let blocks: Vec<_> = region.deref(&self.context).iter(&self.context).collect();
299	            if blocks.len() != 1 {
300	                return Err(CompileError::InvalidModule {
301	                    message: format!(
302	                        "cannot mark `{symbol}` as a kernel: the module has {} top-level blocks, expected exactly one",
303	                        blocks.len()
304	                    ),
305	                });
306	            }
307	            let block = blocks[0];
308	            let mut found = None;
309	            for operation in block.deref(&self.context).iter(&self.context) {
310	                let Some(candidate) =
311	                    Operation::get_op::<dialect_mir::ops::MirFuncOp>(operation, &self.context)
312	                else {
313	                    continue;
314	                };
315	                let operation_ref = candidate.get_operation().deref(&self.context);
316	                let Some(symbol_attr) = operation_ref
317	                    .attributes
318	                    .get::<IdentifierAttr>(&ATTR_KEY_SYM_NAME)
319	                else {
320	                    return Err(CompileError::InvalidModule {
321	                        message:
322	                            "cannot mark a kernel: a top-level dialect-mir function has no symbol"
323	                                .to_string(),
324	                    });
325	                };
326	                let candidate_symbol: Identifier = symbol_attr.clone().into();
327	                if candidate_symbol.to_string() != symbol {
328	                    continue;
329	                }
330	                if found.replace(operation).is_some() {
331	                    return Err(CompileError::InvalidModule {
332	                        message: format!(
333	                            "cannot mark `{symbol}` as a kernel: duplicate top-level dialect-mir functions"
334	                        ),
335	                    });
336	                }
337	            }
338	            found.ok_or_else(|| CompileError::InvalidModule {
339	                message: format!(
340	                    "cannot mark `{symbol}` as a kernel: no top-level dialect-mir function has that symbol"
341	                ),
342	            })?
343	        };
344	
345	        let key: Identifier = "gpu_kernel"
346	            .try_into()
347	            .expect("gpu_kernel is a valid Pliron identifier");
348	        function
349	            .deref_mut(&self.context)
350	            .attributes
351	            .set(key, StringAttr::new("true".to_string()));
352	        Ok(())
353	    }
354	}
355	
356	/// Explicit, reusable pair of LLVM tools.
357	#[derive(Clone, Debug)]
358	pub struct Toolchain {
359	    inner: LlvmToolchain,
360	    diagnostics: Vec<Diagnostic>,
361	}
362	
363	impl Toolchain {
364	    /// Discover LLVM 21+ tools from the Rust sysroot and `PATH`.
365	    ///
366	    /// Discovery is explicit and does not read cuda-oxide environment knobs.
367	    /// It may return a toolchain without `opt`; that toolchain can compile only
368	    /// with [`Optimization::None`].
369	    pub fn discover() -> Result<Self, CompileError> {
370	        let opts = BackendOptions::default();
371	        let inner = LlvmToolchain::resolve(&opts).ok_or_else(|| CompileError::Toolchain {
372	            message: "no runnable LLVM 21+ `llc` was found in the Rust sysroot or PATH".to_string(),
373	        })?;
374	        validate_llvm_major("llc", inner.llc_major)?;
375	        let diagnostics = inner
376	            .diagnostics
377	            .iter()
378	            .cloned()
379	            .map(|message| Diagnostic::warning(CompilationStage::Toolchain, message))
380	            .collect();
381	        Ok(Self { inner, diagnostics })
382	    }
383	
384	    /// Use explicit LLVM tools, verifying that they run and share one major.
385	    pub fn from_paths(llc: impl Into<PathBuf>, opt: Option<PathBuf>) -> Result<Self, CompileError> {
386	        let llc = llc.into();
387	        let llc_text = llc.to_string_lossy().into_owned();
388	        let llc_tool = probe_runnable(&llc_text).ok_or_else(|| CompileError::Toolchain {
389	            message: format!("`{llc_text} --version` did not run successfully"),
390	        })?;
391	        validate_llvm_major("llc", llc_tool.major)?;
392	
393	        let opt = opt
394	            .map(|path| {
395	                let text = path.to_string_lossy().into_owned();
396	                probe_runnable(&text).ok_or_else(|| CompileError::Toolchain {
397	                    message: format!("`{text} --version` did not run successfully"),
398	                })
399	            })
400	            .transpose()?;
401	
402	        if let Some(opt) = &opt {
403	            validate_llvm_major("opt", opt.major)?;
404	            if opt.major != llc_tool.major {
405	                return Err(CompileError::Toolchain {
406	                    message: format!(
407	                        "LLVM major mismatch: llc is {}, but opt is {}",
408	                        llc_tool.major.unwrap(),
409	                        opt.major.unwrap()
410	                    ),
411	                });
412	            }
413	        }
414	
415	        Ok(Self {
416	            inner: LlvmToolchain {
417	                llc_path: llc_tool.path,
418	                llc_major: llc_tool.major,
419	                llc_from_env: false,
420	                opt: opt.map(|tool| OptTool {
421	                    path: tool.path,
422	                    major: tool.major,
423	                }),
424	                diagnostics: Vec::new(),
425	            },
426	            diagnostics: Vec::new(),
427	        })
428	    }
429	
430	    /// Selected `llc` path.
431	    pub fn llc_path(&self) -> &Path {
432	        Path::new(&self.inner.llc_path)
433	    }
434	
435	    /// Selected `opt` path, or `None` when optimization is unavailable.
436	    pub fn opt_path(&self) -> Option<&Path> {
437	        self.inner.opt.as_ref().map(|opt| Path::new(&opt.path))
438	    }
439	
440	    /// Diagnostics recorded while selecting a matched tool pair.
441	    pub fn diagnostics(&self) -> &[Diagnostic] {
442	        &self.diagnostics
443	    }
444	}
445	
446	fn validate_llvm_major(tool: &str, major: Option<u32>) -> Result<(), CompileError> {
447	    match major {
448	        Some(major) if major >= 21 => Ok(()),
449	        Some(major) => Err(CompileError::Toolchain {
450	            message: format!("{tool} reports LLVM {major}; cuda-oxide requires LLVM 21 or newer"),
451	        }),
452	        None => Err(CompileError::Toolchain {
453	            message: format!("could not parse the LLVM major from `{tool} --version`"),
454	        }),
455	    }
456	}
457	
458	/// Reusable standalone compiler.
459	#[derive(Clone, Debug)]
460	pub struct Compiler {
461	    toolchain: Toolchain,
462	}
463	
464	impl Compiler {
465	    /// Create a compiler that reuses `toolchain` for every invocation.
466	    pub fn new(toolchain: Toolchain) -> Self {
467	        Self { toolchain }
468	    }
469	
470	    /// Explicit convenience for callers that want default tool discovery.
471	    pub fn discover() -> Result<Self, CompileError> {
472	        Toolchain::discover().map(Self::new)
473	    }
474	
475	    /// The explicit LLVM toolchain used by this compiler.
476	    pub fn toolchain(&self) -> &Toolchain {
477	        &self.toolchain
478	    }
479	
480	    /// Compile a module without modifying its caller-visible IR.
481	    pub fn compile(
482	        &self,
483	        module: &mut CodegenModule,
484	        options: &CompileOptions,
485	    ) -> Result<Compilation, CompileError> {
486	        if options.debug_info == DebugInfo::Full && options.optimization != Optimization::None {
487	            return Err(CompileError::InvalidOptions {
488	                message: "full variable debug information requires Optimization::None".to_string(),
489	            });
490	        }
491	        if options.optimization == Optimization::O2 && self.toolchain.inner.opt.is_none() {
492	            return Err(CompileError::OptimizationUnavailable {
493	                message:
494	                    "Optimization::O2 requires an `opt` binary with the same LLVM major as llc"
495	                        .to_string(),
496	            });
497	        }
498	
499	        let ctx = &mut module.context;
500	        let source_module = module.module.get_operation();
501	        source_module
502	            .try_deref(ctx)
503	            .map_err(|error| CompileError::InvalidModule {
504	                message: format!("the owned module operation is no longer valid: {error:?}"),
505	            })?;
506	        if Operation::get_op::<ModuleOp>(source_module, ctx).is_none() {
507	            return Err(CompileError::InvalidModule {
508	                message: "the owned module pointer no longer refers to a builtin.module"
509	                    .to_string(),
510	            });
511	        }
512	        let mut mapper = IrMapping::new();
513	        let mut rewriter = IRRewriter::<DummyListener>::default();
514	        let cloned = clone_operation(source_module, ctx, &mut rewriter, &mut mapper);
515	        let result = self.compile_clone(ctx, cloned, options);
516	        Operation::erase(cloned, ctx);
517	        result
518	    }
519	
520	    fn compile_clone(
521	        &self,
522	        ctx: &mut Context,
523	        module: pliron::context::Ptr<Operation>,
524	        options: &CompileOptions,
525	    ) -> Result<Compilation, CompileError> {
526	        let debug_kind = match options.debug_info {
527	            DebugInfo::None => DebugKind::Off,
528	            DebugInfo::Full => DebugKind::Full,
529	        };
530	        let scratch = ScratchDirectory::new()?;
531	        let ll_path = scratch.path().join("module.ll");
532	        let ptx_path = scratch.path().join("module.ptx");
533	        let backend_options = BackendOptions {
534	            target_arch: Some(options.target.sm()),
535	            device_arch_hint: None,
536	            no_opt: options.optimization == Optimization::None,
537	            no_fma: !options.fma_contraction,
538	            verbose: false,
539	            llc_override: None,
540	            opt_override: None,
541	        };
542	        let request = ModulePipelineRequest::for_standalone_ptx(
543	            &backend_options,
544	            debug_kind,
545	            &self.toolchain.inner,
546	            OutputFiles {
547	                llvm_ir: &ll_path,
548	                ptx: &ptx_path,
549	                stale_before_export: &[],
550	            },
551	        );
552	
553	        (|| {
554	            let generated =
555	                compile_translated_module(ctx, module, &request).map_err(CompileError::from)?;
556	            debug_assert_eq!(generated.artifact_kind, ModuleArtifactKind::Ptx);
557	            let ptx = std::fs::read(&ptx_path).map_err(|source| CompileError::Io {
558	                action: "read generated PTX",
559	                path: ptx_path.clone(),
560	                source,
561	            })?;
562	            let target = Target::parse(&generated.target)?;
563	            let mut diagnostics = self.toolchain.diagnostics.clone();
564	            diagnostics.push(Diagnostic::note(
565	                CompilationStage::Codegen,
566	                format!("generated PTX for {target}"),
567	            ));
568	            Ok(Compilation {
569	                ptx,
570	                target,
571	                diagnostics,
572	            })
573	        })()
574	    }
575	}
576	
577	struct ScratchDirectory {
578	    path: PathBuf,
579	}
580	
581	impl ScratchDirectory {
582	    fn new() -> Result<Self, CompileError> {
583	        let root = std::env::temp_dir();
584	        for _ in 0..32 {
585	            let unique = std::time::SystemTime::now()
586	                .duration_since(std::time::UNIX_EPOCH)
587	                .map(|duration| duration.as_nanos())
588	                .unwrap_or(0);
589	            let call = COMPILATION_COUNTER.fetch_add(1, Ordering::Relaxed);
590	            let path = root.join(format!(
591	                "cuda_oxide_codegen_{}_{}_{}",
592	                std::process::id(),
593	                unique,
594	                call
595	            ));
596	            let mut builder = std::fs::DirBuilder::new();
597	            #[cfg(unix)]
598	            {
599	                use std::os::unix::fs::DirBuilderExt;
600	                builder.mode(0o700);
601	            }
602	            match builder.create(&path) {
603	                Ok(()) => return Ok(Self { path }),
604	                Err(error) if error.kind() == std::io::ErrorKind::AlreadyExists => continue,
605	                Err(source) => {
606	                    return Err(CompileError::Io {
607	                        action: "create compilation scratch directory",
608	                        path,
609	                        source,
610	                    });
611	                }
612	            }
613	        }
614	        Err(CompileError::Io {
615	            action: "create a unique compilation scratch directory",
616	            path: root,
617	            source: std::io::Error::new(
618	                std::io::ErrorKind::AlreadyExists,
619	                "32 atomically-created names already existed",
620	            ),
621	        })
622	    }
623	
624	    fn path(&self) -> &Path {
625	        &self.path
626	    }
627	}
628	
629	impl Drop for ScratchDirectory {
630	    fn drop(&mut self) {
631	        let _ = std::fs::remove_dir_all(&self.path);
632	    }
633	}
634	
635	/// Successful PTX compilation.
636	#[derive(Clone, Debug)]
637	pub struct Compilation {
638	    ptx: Vec<u8>,
639	    target: Target,
640	    diagnostics: Vec<Diagnostic>,
641	}
642	
643	impl Compilation {
644	    /// Generated PTX bytes.
645	    pub fn ptx(&self) -> &[u8] {
646	        &self.ptx
647	    }
648	
649	    /// Consume the result and return its PTX bytes.
650	    pub fn into_ptx(self) -> Vec<u8> {
651	        self.ptx
652	    }
653	
654	    /// Concrete CUDA target recorded in the PTX.
655	    pub fn target(&self) -> &Target {
656	        &self.target
657	    }
658	
659	    /// Non-fatal diagnostics retained during compilation.
660	    pub fn diagnostics(&self) -> &[Diagnostic] {
661	        &self.diagnostics
662	    }
663	}
664	
665	/// Structured failure from the experimental compiler.
666	#[derive(Debug, thiserror::Error)]
667	#[non_exhaustive]
668	pub enum CompileError {
669	    /// The requested Pliron symbol name is invalid.
670	    #[error("invalid module name `{name}`")]
671	    InvalidModuleName {
672	        /// Rejected module name.
673	        name: String,
674	    },
675	    /// CUDA target text could not be parsed.
676	    #[error("invalid CUDA target `{target}`: {reason}")]
677	    InvalidTarget {
678	        /// Rejected target text.
679	        target: String,
680	        /// Parser explanation.
681	        reason: String,
682	    },
683	    /// The owned top-level module was erased or replaced through an edit.
684	    #[error("invalid codegen module: {message}")]
685	    InvalidModule {
686	        /// Validation detail.
687	        message: String,
688	    },
689	    /// Compile options conflict with one another.
690	    #[error("invalid compile options: {message}")]
691	    InvalidOptions {
692	        /// Validation detail.
693	        message: String,
694	    },
695	    /// LLVM tools were missing, too old, or from different releases.
696	    #[error("LLVM toolchain is unavailable or incompatible: {message}")]
697	    Toolchain {
698	        /// Tool discovery or compatibility detail.
699	        message: String,
700	    },
701	    /// Optimization was requested without a usable matching `opt`.
702	    #[error("optimization is unavailable: {message}")]
703	    OptimizationUnavailable {
704	        /// Missing-tool detail.
705	        message: String,
706	    },
707	    /// The requested LLVM optimization pass failed.
708	    #[error("LLVM optimization failed: {message}")]
709	    OptimizationFailed {
710	        /// Tool failure and captured stderr.
711	        message: String,
712	    },
713	    /// Input or transformed IR failed structural verification.
714	    #[error("input verification failed: {message}")]
715	    Verification {
716	        /// Verifier explanation.
717	        message: String,
718	        /// Printed failing operation, when Pliron identified one.
719	        operation: Option<String>,
720	    },
721	    /// MIR operations could not be lowered to the LLVM dialect.
722	    #[error("MIR to LLVM lowering failed: {message}")]
723	    Lowering {
724	        /// Lowering explanation.
725	        message: String,
726	    },
727	    /// The lowered LLVM-dialect module failed structural verification.
728	    #[error("lowered LLVM module verification failed: {message}")]
729	    LoweredVerification {
730	        /// Verifier explanation.
731	        message: String,
732	        /// Printed failing operation, when Pliron identified one.
733	        operation: Option<String>,
734	    },
735	    /// V1 found declarations that require a link step it does not provide.
736	    #[error("standalone PTX cannot resolve external symbols: {symbols:?}")]
737	    UnsupportedLinking {
738	        /// Sorted, deduplicated unresolved symbol names.
739	        symbols: Vec<String>,
740	    },
741	    /// LLVM text export failed.
742	    #[error("LLVM IR export failed: {message}")]
743	    Export {
744	        /// Exporter explanation.
745	        message: String,
746	    },
747	    /// `llc` failed or the generated PTX could not be read.
748	    #[error("PTX code generation failed: {message}")]
749	    Codegen {
750	        /// Tool failure and captured stderr.
751	        message: String,
752	    },
753	    /// Scratch artifact I/O failed.
754	    #[error("failed to {action} at {}: {source}", path.display())]
755	    Io {
756	        /// Operation attempted.
757	        action: &'static str,
758	        /// Affected path.
759	        path: PathBuf,
760	        /// Operating-system error.
761	        #[source]
762	        source: std::io::Error,
763	    },
764	}
765	
766	impl CompileError {
767	    /// Compiler stage that failed.
768	    pub fn stage(&self) -> CompilationStage {
769	        match self {
770	            Self::InvalidModuleName { .. }
771	            | Self::InvalidTarget { .. }
772	            | Self::InvalidModule { .. }
773	            | Self::InvalidOptions { .. } => CompilationStage::Input,
774	            Self::Toolchain { .. } => CompilationStage::Toolchain,
775	            Self::OptimizationUnavailable { .. } | Self::OptimizationFailed { .. } => {
776	                CompilationStage::Optimization
777	            }
778	            Self::Verification { .. } => CompilationStage::MirPreparation,
779	            Self::Lowering { .. } | Self::LoweredVerification { .. } => CompilationStage::Lowering,
780	            Self::UnsupportedLinking { .. } => CompilationStage::Linking,
781	            Self::Export { .. } => CompilationStage::Export,
782	            Self::Codegen { .. } | Self::Io { .. } => CompilationStage::Codegen,
783	        }
784	    }
785	
786	    /// Convert this failure to a structured error diagnostic.
787	    pub fn diagnostic(&self) -> Diagnostic {
788	        Diagnostic {
789	            level: DiagnosticLevel::Error,
790	            stage: self.stage(),
791	            message: self.to_string(),
792	        }
793	    }
794	}
795	
796	impl From<PipelineError> for CompileError {
797	    fn from(error: PipelineError) -> Self {
798	        match error {
799	            PipelineError::Verification {
800	                message, operation, ..
801	            } => Self::Verification { message, operation },
802	            PipelineError::Lowering(message) => Self::Lowering { message },
803	            PipelineError::LoweredVerification { message, operation } => {
804	                Self::LoweredVerification { message, operation }
805	            }
806	            PipelineError::UnsupportedLinking { symbols } => Self::UnsupportedLinking { symbols },
807	            PipelineError::Export(message) => Self::Export { message },
808	            PipelineError::PtxGeneration(message) => Self::Codegen { message },
809	            PipelineError::Optimization(message) => Self::OptimizationFailed { message },
810	            PipelineError::NoBody(message) | PipelineError::Translation(message) => {
811	                Self::Verification {
812	                    message,
813	                    operation: None,
814	                }
815	            }
816	        }
817	    }
818	}
