192	    }
193	
194	    // Calls need structured extern declarations before lowering so pointer
195	    // address spaces are preserved by the call converter.
196	    if !request.device_externs.is_empty() {
197	        if request.trace.verbose {
198	            request.trace.emit(format!(
199	                "\n=== Adding {} device extern declarations ===",
200	                request.device_externs.len()
201	            ));
202	        }
203	        add_device_extern_declarations(ctx, module, request.device_externs)?;
204	    }
205	
206	    if request.trace.verbose {
207	        request
208	            .trace
209	            .emit("\n=== Lowering dialect-mir → LLVM dialect ===");
210	    }
211	    lower_to_llvm(ctx, module, !request.backend.no_fma)?;
212	
213	    let needs_libdevice = module_uses_libdevice(ctx, module);
214	    let emit_nvvm_ir = should_emit_nvvm_ir(request.output_policy, needs_libdevice);
215	    let requested_nvvm_ir = matches!(
216	        request.output_policy,
217	        OutputPolicy::ExternalLinkAllowed {
218	            request_nvvm_ir: true
219	        }
220	    );
221	    if needs_libdevice && !requested_nvvm_ir && emit_nvvm_ir && request.trace.verbose {
222	        request.trace.emit(
223	            "\n=== Detected CUDA libdevice (`__nv_*`) calls; \
224	             auto-emitting NVVM IR (skip llc) ===",
225	        );
226	    }
227	
228	    // NVVM pointer syntax depends on the target. Detect the feature floor from
229	    // the same pre-legalization text the ordinary PTX path would inspect.
230	    let automatic_features = if emit_nvvm_ir {
231	        let preview = render_llvm_ir(
232	            ctx,
233	            module,
234	            request.device_externs,
235	            false,
236	            None,
237	            request.debug_kind,
238	        )?;
239	        Some(detect_features_in_llvm_text(&preview))
240	    } else {
241	        None
242	    };
243	
244	    let (nvvm_target, nvvm_dialect) = if emit_nvvm_ir {
245	        let target = resolve_nvvm_target(
246	            request.backend.target_arch.as_deref(),
247	            request.backend.device_arch_hint.as_deref(),
248	            automatic_features,
249	        )?;
250	        let dialect = if target.uses_legacy_llvm() {
251	            NvvmIrDialect::LegacyLlvm7
252	        } else {
253	            NvvmIrDialect::Modern
254	        };
255	        validate_nvvm_debug_support(&target, dialect, request.debug_kind)?;
256	        (Some(target), Some(dialect))
257	    } else {
258	        (None, None)
259	    };
260	
261	    if let Some(dialect) = nvvm_dialect {
262	        if request.trace.verbose {
263	            if dialect == NvvmIrDialect::LegacyLlvm7 {
264	                request
265	                    .trace
266	                    .emit("\n=== Legalizing LLVM dialect for legacy NVVM ===");
267	            } else {
268	                request
269	                    .trace
270	                    .emit("\n=== Legalizing NVVM bit-intrinsic widths ===");
271	            }
272	        }
273	        nvvm_transforms::legalize_for_nvvm(ctx, module, dialect)
274	            .map_err(|error| PipelineError::Lowering(error.disp(ctx).to_string()))?;
275	    }
276	
277	    if request.trace.dump_llvm {
278	        request.trace.emit("\n=== LLVM dialect (pre-verify) ===");
279	        request
280	            .trace
281	            .emit(format!("{}", module.deref(ctx).disp(ctx)));
282	    }
283	    if request.trace.verbose {
284	        request.trace.emit("=== Verifying LLVM dialect module ===");
285	    }
286	    verify_operation(ctx, module, "llvm module").map_err(as_lowered_verification)?;
287	    if request.trace.verbose {
288	        request.trace.emit("LLVM dialect verification successful ✓");
289	    }
290	
291	    if matches!(request.output_policy, OutputPolicy::SelfContainedPtx) {
292	        let symbols = unresolved_external_symbols(ctx, module);
293	        if !symbols.is_empty() {
294	            return Err(PipelineError::UnsupportedLinking { symbols });
295	        }
296	    }
297	
298	    if request.trace.verbose {
299	        let mode = if emit_nvvm_ir { "NVVM IR" } else { "PTX" };
300	        request
301	            .trace
302	            .emit(format!("\n=== Exporting to LLVM IR ({mode} mode) ==="));
303	    }
304	    remove_stale_files(request.files.stale_before_export)?;
305	    export_llvm_ir(
306	        ctx,
307	        module,
308	        request.device_externs,
309	        request.files.llvm_ir,
310	        emit_nvvm_ir,
311	        nvvm_dialect,
312	        request.debug_kind,
313	    )?;
314	    if request.trace.verbose {
315	        request.trace.emit(format!(
316	            "LLVM IR written to {}",
317	            request.files.llvm_ir.display()
318	        ));
319	    }
320	
321	    if emit_nvvm_ir {
322	        if request.trace.verbose {
323	            let reason = if needs_libdevice {
324	                "libdevice present"
325	            } else {
326	                "NVVM IR requested"
327	            };
328	            request.trace.emit(format!(
329	                "\n=== Skipping llc ({reason}); consumer owns libNVVM/nvJitLink build ==="
330	            ));
331	        }
332	        return Ok(ModulePipelineOutput {
333	            artifact_kind: ModuleArtifactKind::NvvmIr,
334	            target: nvvm_target
335	                .expect("NVVM target was resolved before export")
336	                .sm(),
337	            diagnostics: Vec::new(),
338	        });
339	    }
340	
341	    if request.trace.verbose {
342	        request.trace.emit("\n=== Generating PTX ===");
343	    }
344	    let generated = match request.toolchain {
345	        ToolchainPolicy::Discover => generate_ptx(
346	            request.files.llvm_ir,
347	            request.files.ptx,
348	            request.debug_kind,
349	            request.backend,
350	            request.trace.sink,
351	        )?,
352	        ToolchainPolicy::Explicit(toolchain) => GeneratedPtx {
