1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! Matched-pair resolution of the LLVM `opt` and `llc` binaries.
7	//!
8	//! The middle-end (`opt -O2`) and the backend (`llc`) must come from the
9	//! same LLVM major release: textual IR is not stable across majors. The
10	//! concrete failure that motivated this module (issue #150): LLVM 22's
11	//! inliner emits the new sizeless `llvm.lifetime.start(ptr)` intrinsic form
12	//! (the `i64` size parameter was removed in LLVM 22), which an LLVM 21
13	//! `llc` rejects with `Intrinsic has incorrect argument type!`. Before this
14	//! module existed, `optimize_ll` discovered `opt` with its own precedence
15	//! and never consulted the `llc` that would consume its output, so a user
16	//! pinning `CUDA_OXIDE_LLC` to an LLVM 21 `llc` (documented as supported)
17	//! still got the rustc sysroot's LLVM 22 `opt`.
18	//!
19	//! [`LlvmToolchain::resolve`] therefore picks `llc` first (it is the tool
20	//! users pin via `CUDA_OXIDE_LLC` and the one with the hard version floor),
21	//! reads its major from `llc --version`, then selects an `opt` of the SAME
22	//! major:
23	//!
24	//! 1. An explicit `opt_override` (historically `CUDA_OXIDE_OPT`) is always
25	//!    respected, but a major mismatch against the chosen `llc` records a
26	//!    prominent diagnostic naming both binaries.
27	//! 2. Otherwise the `opt` sitting next to the chosen `llc` (LLVM installs
28	//!    keep tools side by side) is preferred, provided its major matches.
29	//! 3. Otherwise the remaining candidates (sysroot llvm-tools `opt`,
30	//!    `opt-22` / `opt-21` / `opt` on `PATH`) are considered, filtered to
31	//!    the same major as `llc`.
32	//! 4. If no same-major `opt` exists, resolution records a diagnostic naming
33	//!    every rejected candidate. The experimental API treats requested
34	//!    optimization as strict; the legacy rustc path retains its unoptimized
35	//!    fallback.
36	
37	use crate::options::BackendOptions;
38	use std::path::Path;
39	
40	/// A resolved `opt` binary and the LLVM major it reported (if parseable).
41	// mir-importer pipeline plumbing; not part of the frontend contract.
42	#[doc(hidden)]
43	#[derive(Debug, Clone, PartialEq, Eq)]
44	pub struct OptTool {
45	    pub path: String,
46	    pub major: Option<u32>,
47	}
48	
49	/// The `opt` / `llc` pair the pipeline will use, resolved once per
50	/// compilation so both `optimize_ll` and `generate_ptx` agree on it.
51	/// Future version-conditional IR emission should key off `llc_major` here
52	/// rather than re-probing binaries.
53	// mir-importer pipeline plumbing; not part of the frontend contract.
54	#[doc(hidden)]
55	#[derive(Debug, Clone)]
56	pub struct LlvmToolchain {
57	    /// The `llc` binary that will produce PTX.
58	    pub llc_path: String,
59	    /// `llc`'s LLVM major (from `llc --version`), `None` if unparseable.
60	    pub llc_major: Option<u32>,
61	    /// Whether `llc_path` came from `opts.llc_override` (historically
62	    /// `CUDA_OXIDE_LLC`; affects messages).
63	    pub llc_from_env: bool,
64	    /// The matched `opt` for the middle-end; `None` skips `opt -O2`
65	    /// (either `opts.no_opt` or no same-major `opt` exists).
66	    pub opt: Option<OptTool>,
67	    /// Tool-selection diagnostics for the caller to report or retain.
68	    pub diagnostics: Vec<String>,
69	}
70	
71	impl LlvmToolchain {
72	    /// Resolves the `opt` / `llc` pair. Returns `None` when no `llc`
73	    /// candidate is runnable at all (the caller reports the existing
74	    /// "No working llc found" error).
75	    ///
76	    /// Selection warnings are returned in [`LlvmToolchain::diagnostics`].
77	    /// Library code never writes them directly to stdout or stderr.
78	    pub fn resolve(opts: &BackendOptions) -> Option<Self> {
79	        let (llc_path, llc_major, llc_from_env) = resolve_llc(opts)?;
80	
81	        let (opt, diagnostics) = if opts.no_opt {
82	            // Explicit user intent: skip the middle-end, no warning needed.
83	            (None, Vec::new())
84	        } else {
85	            let explicit = opts.opt_override.as_ref().map(|path| {
86	                let path = path.to_string_lossy().into_owned();
87	                let major = probe_runnable(&path).and_then(|t| t.major);
88	                OptTool { path, major }
89	            });
90	            let sibling = sibling_opt_candidates(&llc_path)
91	                .into_iter()
92	                .find_map(|c| probe_runnable(&c));
93	            let mut others: Vec<OptTool> = Vec::new();
94	            if let Some(p) = sysroot_tool("opt")
95	                && let Some(t) = probe_runnable(&p)
96	            {
97	                others.push(t);
98	            }
99	            for name in ["opt-22", "opt-21", "opt"] {
100	                if let Some(t) = probe_runnable(name) {
101	                    others.push(t);
102	                }
103	            }
104	
105	            let (choice, diagnostics) = choose_opt(&llc_path, llc_major, explicit, sibling, others);
106	            (choice.into_opt(), diagnostics)
107	        };
108	
109	        Some(LlvmToolchain {
110	            llc_path,
111	            llc_major,
112	            llc_from_env,
113	            opt,
114	            diagnostics,
115	        })
116	    }
117	}
118	
119	/// Resolves the `llc` binary with the documented precedence:
120	/// `opts.llc_override` (historically `CUDA_OXIDE_LLC`; used exclusively,
121	/// even if it cannot be probed - the pinned binary's own errors must
122	/// surface), then the Rust toolchain's llvm-tools `llc`, then `llc-22` /
123	/// `llc-21` on `PATH` (first runnable wins). Returns `(path, major,
124	/// from_override)`.
125	fn resolve_llc(opts: &BackendOptions) -> Option<(String, Option<u32>, bool)> {
126	    if let Some(path) = &opts.llc_override {
127	        let path = path.to_string_lossy().into_owned();
128	        let major = probe_runnable(&path).and_then(|t| t.major);
129	        return Some((path, major, true));
130	    }
131	
132	    let mut candidates: Vec<String> = Vec::new();
133	    if let Some(p) = sysroot_tool("llc") {
134	        candidates.push(p);
135	    }
136	    candidates.push("llc-22".to_string());
137	    candidates.push("llc-21".to_string());
138	
139	    candidates
140	        .into_iter()
141	        .find_map(|c| probe_runnable(&c))
142	        .map(|t| (t.path, t.major, false))
143	}
144	
145	/// The result of [`choose_opt`]: either a usable `opt`, or skip the
146	/// middle-end entirely.
147	#[derive(Debug, PartialEq, Eq)]
148	pub(crate) enum OptChoice {
149	    Use(OptTool),
150	    Skip,
151	}
152	
153	impl OptChoice {
154	    /// Converts the decision into the `Option<OptTool>` the toolchain
155	    /// stores (`Skip` = no middle-end, same as `opts.no_opt`).
156	    fn into_opt(self) -> Option<OptTool> {
157	        match self {
158	            OptChoice::Use(t) => Some(t),
159	            OptChoice::Skip => None,
160	        }
161	    }
162	}
163	
164	/// Pure decision logic for picking an `opt` matched to the chosen `llc`.
165	/// Returns the choice plus any warnings the caller should print.
166	///
167	/// - `explicit` (`CUDA_OXIDE_OPT`) always wins, with a prominent warning
168	///   when its major differs from `llc`'s.
169	/// - `sibling` is the `opt` co-located with `llc`; it is accepted when its
170	///   major matches, or when `llc`'s major is unknown (same install
171	///   directory implies the same release).
172	/// - `others` are accepted only on an exact major match, which requires
173	///   `llc`'s major to be known.
174	/// - Otherwise: skip the middle-end, warning with every rejected candidate.
175	pub(crate) fn choose_opt(
176	    llc_path: &str,
177	    llc_major: Option<u32>,
178	    explicit: Option<OptTool>,
179	    sibling: Option<OptTool>,
180	    others: Vec<OptTool>,
181	) -> (OptChoice, Vec<String>) {
182	    let mut warnings = Vec::new();
183	
184	    if let Some(t) = explicit {
185	        if let (Some(opt_major), Some(llc_major)) = (t.major, llc_major)
186	            && opt_major != llc_major
187	        {
188	            warnings.push(format!(
189	                "warning: LLVM version mismatch between opt and llc:\n\
190	                 warning:   CUDA_OXIDE_OPT = {} (LLVM {opt_major})\n\
191	                 warning:   llc            = {llc_path} (LLVM {llc_major})\n\
192	                 warning: mixing majors can produce IR the older tool rejects (e.g. LLVM 22's\n\
193	                 warning: sizeless llvm.lifetime.start/end form fails LLVM 21's llc verifier).\n\
194	                 warning: proceeding anyway because CUDA_OXIDE_OPT is an explicit override;\n\
195	                 warning: unset it (or point it at an LLVM {llc_major} opt) to fix the mismatch.",
196	                t.path
197	            ));
198	        }
199	        return (OptChoice::Use(t), warnings);
200	    }
201	
202	    let mut rejected: Vec<OptTool> = Vec::new();
203	
204	    if let Some(s) = sibling {
205	        if llc_major.is_none() || s.major == llc_major {
206	            return (OptChoice::Use(s), warnings);
207	        }
208	        rejected.push(s);
209	    }
210	
211	    if llc_major.is_some() {
212	        for t in others {
213	            if t.major == llc_major {
214	                return (OptChoice::Use(t), warnings);
215	            }
216	            rejected.push(t);
217	        }
218	    } else {
219	        // llc's major is unknown and there is no co-located opt: no
220	        // candidate can be verified to match, so none is acceptable.
221	        rejected.extend(others);
222	    }
223	
224	    let mut msg = format!(
225	        "LLVM optimization is unavailable: no opt matching the chosen llc.\n\
226	         warning:   llc: {}",
227	        describe_tool(llc_path, llc_major)
228	    );
229	    if rejected.is_empty() {
230	        msg.push_str("\nwarning:   no opt candidates were found at all.");
231	    } else {
232	        msg.push_str("\nwarning:   rejected opt candidates:");
233	        for t in &rejected {
234	            msg.push_str(&format!(
235	                "\nwarning:     {}",
236	                describe_tool(&t.path, t.major)
237	            ));
238	        }
239	    }
240	    msg.push_str(
241	        "\nwarning:   install an opt of the same LLVM major as llc, explicitly disable \
242	         optimization, or set CUDA_OXIDE_OPT.",
243	    );
244	    warnings.push(msg);
245	
246	    (OptChoice::Skip, warnings)
247	}
248	
249	/// `"path (LLVM 21)"` or `"path (unknown LLVM version)"` for messages.
250	pub(crate) fn describe_tool(path: &str, major: Option<u32>) -> String {
251	    match major {
252	        Some(m) => format!("{path} (LLVM {m})"),
253	        None => format!("{path} (unknown LLVM version)"),
254	    }
255	}
256	
257	/// Extracts the LLVM major from `--version` output. Handles both distro
258	/// (`"Ubuntu LLVM version 21.1.8"`) and rustc llvm-tools
259	/// (`"LLVM version 22.1.2-rust-1.96.0-nightly"`) banners.
260	pub(crate) fn parse_llvm_major(version_output: &str) -> Option<u32> {
261	    const NEEDLE: &str = "LLVM version ";
262	    let idx = version_output.find(NEEDLE)?;
263	    let rest = &version_output[idx + NEEDLE.len()..];
264	    let digits: String = rest.chars().take_while(|c| c.is_ascii_digit()).collect();
265	    digits.parse().ok()
266	}
267	
268	/// `opt` paths co-located with `llc_path`, most specific first: the
269	/// version-suffixed twin (`/usr/bin/llc-21` -> `/usr/bin/opt-21`), then the
270	/// plain `opt` in the same directory. A bare `llc` name (resolved through
271	/// `PATH`) yields bare `opt` names.
272	pub(crate) fn sibling_opt_candidates(llc_path: &str) -> Vec<String> {
273	    let p = Path::new(llc_path);
274	    let dir = p.parent().filter(|d| !d.as_os_str().is_empty());
275	
276	    let mut names: Vec<String> = Vec::new();
277	    if let Some(suffix) = p
278	        .file_name()
279	        .and_then(|b| b.to_str())
280	        .and_then(|b| b.strip_prefix("llc"))
281	        && !suffix.is_empty()
282	    {
283	        names.push(format!("opt{suffix}"));
284	    }
285	    names.push("opt".to_string());
286	
287	    names
288	        .into_iter()
289	        .map(|n| match dir {
290	            Some(d) => d.join(&n).to_string_lossy().into_owned(),
291	            None => n,
292	        })
293	        .collect()
294	}
295	
296	/// Runs `cmd --version` and, on success, returns the tool with its parsed
297	/// major. `None` means the binary does not exist or is not runnable.
298	pub(crate) fn probe_runnable(cmd: &str) -> Option<OptTool> {
299	    let out = std::process::Command::new(cmd)
300	        .arg("--version")
301	        .output()
302	        .ok()?;
303	    if !out.status.success() {
304	        return None;
305	    }
306	    let stdout = String::from_utf8_lossy(&out.stdout);
307	    Some(OptTool {
308	        path: cmd.to_string(),
309	        major: parse_llvm_major(&stdout),
310	    })
311	}
312	
313	/// Path of `tool` inside the Rust toolchain's llvm-tools component:
314	/// `<sysroot>/lib/rustlib/<host>/bin/<tool>`.
315	fn sysroot_tool(tool: &str) -> Option<String> {
316	    let out = std::process::Command::new("rustc")
317	        .args(["--print", "sysroot", "--print", "host-tuple"])
318	        .output()
319	        .ok()
