196	fn generate_ptx_impl(
197	    ll_path: &Path,
198	    ptx_path: &Path,
199	    debug_kind: DebugKind,
200	    opts: &BackendOptions,
201	    toolchain: &LlvmToolchain,
202	    strict_optimization: bool,
203	    diagnostic_sink: Option<fn(&str)>,
204	) -> Result<GeneratedPtx, PipelineError> {
205	    // Explicit, hard override: `--arch` or a caller-set `opts.target_arch`.
206	    let explicit_override = opts.target_arch.clone();
207	    // Advisory hint: the arch of the GPU in this machine, forwarded by
208	    // `cargo oxide run`. Used only when that GPU can actually run the kernel.
209	    let device_hint = opts.device_arch_hint.clone();
210	
211	    let requirements = detect_module_requirements_in_llvm_file(ll_path)?;
212	    let detected = requirements.features;
213	
214	    // Resolve the final target:
215	    //   1. explicit override -- accepted only if it can lower the kernel's
216	    //      features; reject an invalid floor before llc emits unusable PTX.
217	    //   2. detected-device hint -- used only if that GPU can run the kernel;
218	    //      otherwise we build for the feature floor. The resulting PTX will not
219	    //      load on this GPU, but feature-gated examples handle that at load time
220	    //      (cuModuleLoad reports INVALID_PTX and they skip execution).
221	    //   3. neither set -- the feature floor.
222	    let (target, target_source) = resolve_ptx_target(
223	        explicit_override.as_deref(),
224	        device_hint.as_deref(),
225	        detected,
226	    )?;
