228	    let mut diagnostics = Vec::new();
229	    if opts.verbose {
230	        record_diagnostic(
231	            &mut diagnostics,
232	            diagnostic_sink,
233	            format!("Target: {target} (from {target_source}; detected {detected:?})"),
234	        );
235	    }
236	
237	    validate_target_for_llvm_major(&target, toolchain.llc_major)
238	        .map_err(PipelineError::PtxGeneration)?;
239	
240	    // Run the LLVM middle-end (opt -O2) before llc. Feature detection above
241	    // intentionally reads the original (pre-opt) IR so the target is determined
242	    // by what the source actually needs, not what opt elides.
243	    //
244	    // Full-debug is a `-G`-style build: it keeps every local in memory and
245	    // describes it with `llvm.dbg.declare`. Running `opt -O2` would promote
246	    // those slots to registers and collapse their live ranges, turning most
247	    // in-scope locals into `<optimized out>` under cuda-gdb. So we feed the
248	    // unoptimized IR straight to llc when variable info is requested, matching
249	    // nvcc `-G`. (llc itself is invoked at `-O0` for the same builds below.)
250	    let optimized = if debug_kind.variables_enabled() {
251	        if opts.verbose {
252	            record_diagnostic(
253	                &mut diagnostics,
254	                diagnostic_sink,
255	                "Skipping opt -O2 (full debug keeps locals inspectable)".to_string(),
256	            );
257	        }
258	        None
