261	            optimize_ll(ll_path, toolchain, opts, strict_optimization)?;
262	        for diagnostic in opt_diagnostics.drain(..) {
263	            record_diagnostic(&mut diagnostics, diagnostic_sink, diagnostic);
264	        }
265	        optimized
266	    };
267	    let llc_input: &Path = optimized.as_deref().unwrap_or(ll_path);
268	
269	    let llc_desc = if toolchain.llc_from_env {
270	        format!("llc_override ({})", toolchain.llc_path)
271	    } else {
272	        format!("llc ({})", toolchain.llc_path)
273	    };
274	    if opts.verbose {
275	        let source = if toolchain.llc_from_env {
276	            "from opts.llc_override"
277	        } else {
278	            "auto-detected"
279	        };
280	        record_diagnostic(
281	            &mut diagnostics,
282	            diagnostic_sink,
283	            format!(
284	                "Using llc: {} ({source})",
285	                crate::llvm_tools::describe_tool(&toolchain.llc_path, toolchain.llc_major)
286	            ),
287	        );
288	    }
289	
290	    let mut llc_cmd = std::process::Command::new(&toolchain.llc_path);
291	    llc_cmd
292	        .arg("-march=nvptx64")
293	        .arg(format!("-mcpu={}", target));
294	    if let Some(feature) = required_ptx_feature(&target, requirements.ptx_isa) {
295	        llc_cmd.arg(format!("-mattr={feature}"));
296	    }
297	    // Full-debug (`-G`-style): run llc at -O0 so its own mem2reg/SROA does not
298	    // promote the stack slots we deliberately kept in memory, which would
299	    // invalidate the `llvm.dbg.declare` locations cuda-gdb reads.
300	    if debug_kind.variables_enabled() {
301	        llc_cmd.arg("-O0");
302	    }
303	    // Fuse fmul+fadd/fsub into fma.rn.f32, matching nvcc's default --fmad=true.
304	    // The IR-side `contract` flag (set during lowering when contraction is
305	    // allowed) grants permission; this llc flag activates the NVPTX backend's
306	    // contract mode. `opts.no_fma` (allow_fma_contraction = !no_fma) drives both
307	    // stages, so IR permission and this backend gate cannot disagree.
308	    if !opts.no_fma {
